def gen(rng, size):
    m = rng.randint(1, 20)
    n = rng.randint(1, 20)
    diag = {d: rng.randint(0, 99) for d in range(-(m - 1), n)}
    matrix = [[diag[j - i] for j in range(n)] for i in range(m)]
    if rng.random() < 0.4 and m >= 2 and n >= 2:
        i = rng.randint(1, m - 1)
        j = rng.randint(1, n - 1)
        matrix[i][j] = (matrix[i][j] + rng.randint(1, 99)) % 100
    return [matrix]

