class Solution:
    def isToeplitzMatrix(self, matrix):
        m, n = len(matrix), len(matrix[0])
        from collections import defaultdict
        diags = defaultdict(set)
        for i in range(m):
            for j in range(n):
                diags[j - i].add(matrix[i][j])
        return all(len(vals) == 1 for vals in diags.values())

